import smolagents
import re

def compressed_agent(base_agent):
    class FastAgent(base_agent):
        def _format_prompt(self, messages):
            # Remove verbose reasoning patterns
            compressed = []
            for msg in messages[-4:]:
                if 'reasoning' in msg.get('role', ''):
                    # Keep only final decision
                    msg['content'] = re.sub(r'^.*?Action: ', '', msg['content'])
                compressed.append(msg)
            return super(base_agent, self)._format_prompt(compressed)

    return FastAgent(**base_agent.__dict__)

