import smolagents
from functools import lru_cache

def optimized_agent(tools):
    @lru_cache(maxsize=32)
    def get_tool_schema(tool_name):
        return tools[tool_name].schema

    class CachedAgent(smolagents.Agent):
        def _get_tool_schema(self, tool_name):
            return get_tool_schema(tool_name)

        def __init__(self, *args, **kwargs):
            super().__init__(tools=tools, *args, **kwargs)

    return CachedAgent()

agent = optimized_agent([calculator, search])

import smolagents

def batch_agent(base_agent):
    class BatchAgent(base_agent):
        def run(self, task, max_steps=3):
            # Batch first N reasoning steps
            batched_prompt = f"""
            Solve this in MAX {max_steps} steps total:
            {task}

            Format: <step1>action1</step1><step2>action2</step2>...
            """

            response = self.llm.predict(batched_prompt)
            # Parse multi-step response
            steps = re.findall(r'<step\d+>(.*?)</step\d+>', response)

            for step in steps[:max_steps]:
                self._execute_step(step)

    return BatchAgent(**base_agent.__dict__)
